// TypeScript shapes for `rocky --output json` envelopes.
//
// As of Phase 2, every Rocky CLI command that has a typed Rust output
// struct is consumed via the autogenerated TypeScript interfaces in
// `./generated/`. This file is a thin compatibility shim that re-exports
// the generated types under the legacy Python-flavored names that the
// existing consumers in `src/commands/`, `src/views/`, `src/webviews/`,
// and `src/testExplorer.ts` import.
//
// To regenerate the underlying interfaces, run `just codegen` from the
// monorepo root (or see `editors/vscode/src/types/generated/index.ts`).
//
// As of Phase 2 round 13, ALL CLI commands are typed in Rust, so every
// interface here is an alias to a generated type. There are no more
// hand-written interfaces.

import type {
  ArchiveOutput,
  CatalogOutput,
  CiOutput,
  CompactOutput,
  CompareOutput,
  CompileOutput,
  Diagnostic,
  DiscoverOutput,
  DoctorOutput,
  EncodingRecommendationOutput,
  HealthCheck,
  HistoryOutput,
  HookEntry,
  HooksListOutput,
  HooksTestOutput,
  ImportDbtFailure,
  ImportDbtOutput,
  ImportDbtWarning,
  MetricsOutput,
  NamedStatement,
  OptimizeOutput,
  OptimizeRecommendation as OptimizeRecommendationGen,
  PlanOutput,
  PlannedStatement,
  ProfileStorageOutput,
  RunOutput,
  SourceOutput,
  TableCompareResult,
  TestOutput,
} from "./generated";

// --- Aliases mapping legacy Python-flavored names to the Phase 2 generated types ---

export type DoctorResult = DoctorOutput;
export type DoctorCheck = HealthCheck;

export type OptimizeResult = OptimizeOutput;
export type OptimizeRecommendation = OptimizeRecommendationGen;

export type CompileResult = CompileOutput;
export type CompileDiagnostic = Diagnostic;

export type RunResult = RunOutput;

export type PlanResult = PlanOutput;
export type PlanStatement = PlannedStatement;

export type DiscoverResult = DiscoverOutput;
export type DiscoverSource = SourceOutput;

export type TestResult = TestOutput;

export type CiResult = CiOutput;

export type HistoryResult = HistoryOutput;

export type MetricsResult = MetricsOutput;

// --- Round 13 additions: the previously hand-written interfaces are now
// aliases to the generated types since the underlying Rust commands have
// typed structs. ---

export type CompareResult = CompareOutput;
// CompareResult's per-table breakdown was previously not exported by name;
// expose it now under the previous nested name and the generated name.
export type CompareTableResult = TableCompareResult;

export type CompactResult = CompactOutput;

export type ArchiveResult = ArchiveOutput;
// archive + compact share NamedStatement for the per-step purpose+sql payload.
export type ArchiveStatement = NamedStatement;
export type CompactStatement = NamedStatement;

export type ProfileStorageResult = ProfileStorageOutput;
export type ProfileStorageRecommendation = EncodingRecommendationOutput;

export type ImportDbtResult = ImportDbtOutput;
export type { ImportDbtWarning, ImportDbtFailure };

export type HooksListResult = HooksListOutput;
export type HooksHookEntry = HookEntry;

export type HooksTestResult = HooksTestOutput;

export type CatalogResult = CatalogOutput;
